import { By } from "selenium-webdriver";
import ojwd, { DriverLike, register } from "../../";
import { OjDatePicker } from "./OjDatePicker";
export { OjDatePicker };

/**
 * Create an instance of [[OjDatePicker]].  This function will first wait for
 * the element to appear in the DOM before trying to locate it.
 * @example
 * <code>
 * const el = await ojDatePicker(driver, By.id('my-oj-date-picker'))
 * </code>
 * @param driver A WebDriver/WebElement instance used to locate the component
 * element.
 * @param by The By locator with which to find the element
 */
export async function ojDatePicker(driver: DriverLike, by: By): Promise<OjDatePicker> {
  const webEl = await driver.findElement(by);
  // Check that the element is of type OjDatePicker
  if (!(webEl instanceof OjDatePicker)) {
    const tagName = await webEl.getTagName();
    throw Error(`Locator '${by}' located a <${tagName}>, but expected <oj-date-picker>`);
  }
  return webEl;
}

register("oj-date-picker", OjDatePicker);
